// Extract messaging data from Facebook webhook payload
const entry = $input.first().json.body.entry[0];
const messaging = entry.messaging[0];

// --- 🛑 THE BUG FIX: KILL ECHOES AND RECEIPTS ---
if (messaging.delivery || messaging.read || (messaging.message && messaging.message.is_echo)) {
  return []; 
}
// ------------------------------------------------

const senderId = messaging.sender.id;
const timestamp = messaging.timestamp;

let messageText = '';
let imageUrl = '';
let messageType = 'text';

// Catch standard text and images
if (messaging.message) {
  if (messaging.message.text) {
    messageText = messaging.message.text;
    messageType = 'text';
  }
  if (messaging.message.attachments) {
    const imageAttachment = messaging.message.attachments.find(
      att => att.type === 'image'
    );
    if (imageAttachment) {
      imageUrl = imageAttachment.payload.url;
      messageType = imageUrl ? 'image' : messageType;
    }
  }
}

// Catch Facebook Native Menu button clicks
if (messaging.postback && messaging.postback.payload) {
  messageText = messaging.postback.payload;
  messageType = 'text';
}

return [{
  json: {
    senderId,
    timestamp,
    messageText,
    imageUrl,
    messageType,
    rawMessage: messaging
  }
}];

