const aiResponse = $input.first().json;
const catalogData = $('Prepare Product Catalog').first().json;
const content = aiResponse.choices[0].message.content;

let parsed = { is_payment_slip: false, matched: false, product_name: '' };
try {
  let cleanContent = content.trim();
  if (cleanContent.startsWith('```')) {
    cleanContent = cleanContent.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  }
  parsed = JSON.parse(cleanContent);
} catch (e) {}

return [{
  json: {
    ...catalogData, 
    is_payment_slip: parsed.is_payment_slip || false,
    matched: parsed.matched,
    product_name: parsed.product_name
  }
}];

const msgData = $('Extract Message Data').first().json;
