try {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    const mimeType = $input.first().binary.data.mimeType || 'image/jpeg';
    customerImageData = 'data:' + mimeType + ';base64,' + buffer.toString('base64');
} catch (e) {}

return [{
    json: {
        ...msgData,
        customer_image_data: customerImageData
    }
}];

