// ခြင်းတောင်းထဲ ပစ္စည်းရှိရင်
let cartItemsString = rows[0].json.ai_json;
let formattedList = "";

try {
    // Stringified JSON ဖြစ်နေလျှင် Object အဖြစ် အရင်ပြောင်းမည်
    let cartObject = cartItemsString;
    if (typeof cartItemsString === 'string') {
        cartObject = JSON.parse(cartItemsString);
    }

    // 🎯 ပုံစံအသစ် (Array of Objects) ဖြင့် ဝင်လာခဲ့လျှင်
    if (Array.isArray(cartObject)) {
        cartObject.forEach(item => {
            const itemName = item.product_name || "ပစ္စည်းအမည်မသိ";
            const quantity = item.quantity || 1;
            formattedList += `• ${itemName} x (${quantity}) ခု\n`;
        });
