// ၁။ ပထမဆုံး Webhook မှ ဝင်လာသော Data ကို ယူခြင်း
const webhookData = $('Facebook Webhook').first().json.body.entry[0].messaging[0];
const payload = webhookData.postback?.payload || webhookData.message?.text || "";
const senderId = webhookData.sender.id;

// ၂။ BUY_ နောက်က ပစ္စည်းနာမည်ကို ဖြတ်ယူခြင်း
const productName = payload.replace("BUY_", "").trim();

// ၃။ Get Row(s) မှ ရလာသော ခြင်းတောင်းအဟောင်းကို ယူခြင်း 
const items = $input.all(); 
const dbData = items.length > 0 && Object.keys(items[0].json).length > 0 ? items[0].json : null;

let cart = [];

// Customer အဟောင်းဖြစ်ပြီး ai_json ရှိနေမှသာ ခြင်းတောင်းကို ဆွဲထုတ်မည်
if (dbData && dbData.ai_json) {
    try {
        cart = JSON.parse(dbData.ai_json);
    } catch(e) {}
}

// ၄။ ခြင်းတောင်းထဲသို့ ရွေးလိုက်သော ပစ္စည်း (၁) ခု ထည့်ခြင်း
const existingIndex = cart.findIndex(item => item.product_name === productName);
if (existingIndex > -1) {
    cart[existingIndex].quantity += 1; // ပါပြီးသားဆိုလျှင် ၁ ခု တိုးမည်
} else {
    cart.push({ product_name: productName, quantity: 1 }); // မပါသေးလျှင် အသစ်ထည့်မည်
}

// ၅. Upsert အတွက် Data ပြန်ထုတ်ပေးခြင်း
return [{
    json: {
        sender_id: senderId,
        product_name: productName,
        cart_data: JSON.stringify(cart)
    }
}];
